class Solution:
    def findTheLongestSubstring(self, s):
        """
        :type s: str
        :rtype: int
        """
        # Use bitmask for vowel parity
        vowels = "aeiou"
        state = 0
        seen = {0: -1}  # state: earliest index
        max_len = 0

        for i, char in enumerate(s):
            if char in vowels:
                idx = vowels.index(char)
                state ^= (1 << idx)  # Toggle bit

            if state in seen:
                max_len = max(max_len, i - seen[state])
            else:
                seen[state] = i

        return max_len
